use typed_arena::Arena;
use bumpalo::Bump;
use std::collections::HashMap;

struct GameState {
    entity_id: u32,
    position: (f32, f32, f32),
}

fn main() {
    let bump = Bump::new();
    let mut arena = Arena::<GameState>::new();

    let initial_state1 = GameState { entity_id: 10, position: (1.0, 5.0, 0.0) };
    let initial_state2 = GameState { entity_id: 20, position: (-2.0, 1.0, 0.0) };

    let state1_ptr = arena.alloc(initial_state1);
    let state2_ptr = arena.alloc(initial_state2);

    let mut frame_data: HashMap<u32, Vec<*mut GameState>> = HashMap::new();
    frame_data.insert(0, vec![state1_ptr, state2_ptr]);

    println!("Successfully allocated {} game states in the arena.", arena.len());

    let retrieved_state = unsafe { &*state1_ptr };
    println!("Checking first stored entity: ID {}, Pos {:?}", retrieved_state.entity_id, retrieved_state.position);
}
